        background-color: #ffb7c5;
        border-radius: 50% 0 50% 50%;
        transform: rotate(45deg);
        opacity: 0.8;
      }

      .title-petal-1 { top: -2px; left: 5px; transform: rotate(15deg); }
      .title-petal-2 { bottom: -2px; left: 18px; transform: rotate(-30deg); width: 5px; height: 5px; background-color: #ff91a4;}
      .title-petal-3 { top: 5px; right: 5px; transform: rotate(70deg); }
      .title-petal-4 { bottom: 2px; right: -5px; transform: rotate(-10deg); width: 4px; height: 4px; }


      /* 中间樱花装饰区域 - 展开后渐变显示 */
      .sakura-decoration {
