          <textarea id="raw-markdown" style="display: none;">$1</textarea>
          <!-- 解析出的 HTML 将被注入到这里 -->
          <div class="sakura-content-inner" id="rendered-content">加载中...</div>

          <!-- 底部文字替换 -->
          <div class="sakura-collapse-btn" onclick="toggleCollapsible()">思考过程如上</div>
        </div>
      </div>
    </div>

    <script>
      // 页面加载完毕后，解析 Markdown 文本
      document.addEventListener('DOMContentLoaded', function() {
        const rawElement = document.getElementById('raw-markdown');
        const renderedElement = document.getElementById('rendered-content');

        if (rawElement && renderedElement && typeof marked !== 'undefined') {
          // 获取 textarea 中的原始 markdown 内容
          const mdText = rawElement.value;
          // 调用 marked 解析，并注入 HTML 渲染容器
          renderedElement.innerHTML = marked.parse(mdText);
        }

        // 解析可能改变内容整体高度，更新 iframe
        setTimeout(updateIframeHeight, 100);
      });

      function toggleCollapsible() {
        const collapsible = document.getElementById('sakuraCollapsible');
        const header = collapsible.querySelector('.sakura-header');
        const isExpanded = collapsible.classList.toggle('expanded');
        header.setAttribute('aria-expanded', isExpanded ? 'true' : 'false');

        // 展开时触发花瓣飘落特效
        if (isExpanded) {
          triggerPetalFall();
        }

        // 配合 0.5s 的 CSS transiton 动画时长，在动画开始和结束时都更新高度
        setTimeout(updateIframeHeight, 50);
        setTimeout(updateIframeHeight, 550);
      }

      // 生成飘落花瓣的独立函数
      function triggerPetalFall() {
        const contentBox = document.querySelector('.sakura-content-wrapper'); // 放到内部以免溢出问题
        const petalCount = 8;
        const emojis = ['🌸', '💮'];

        for (let i = 0; i < petalCount; i++) {
          const petal = document.createElement('div');
          petal.className = 'petal-particle';
          petal.innerText = emojis[Math.floor(Math.random() * emojis.length)];

          const size = 10 + Math.random() * 8;
          const startX = 10 + Math.random() * 80;
          const duration = 1.5 + Math.random() * 1.5;
          const delay = Math.random() * 0.5;

          Object.assign(petal.style, {
            fontSize: `${size}px`,
            left: `${startX}%`,
            animationDuration: `${duration}s`,
            animationDelay: `${delay}s`
          });

          contentBox.appendChild(petal);

          setTimeout(() => {
            if (petal.parentNode === contentBox) {
              contentBox.removeChild(petal);
            }
          }, (duration + delay) * 1000);
        }
      }

      function updateIframeHeight() {
        const bodyHeight = document.body.scrollHeight;
        if (window.parent && window.parent !== window) {
          window.parent.postMessage({ type: 'resizeIframe', height: bodyHeight }, '*');
        }
      }

      document.addEventListener('keydown', function (event) {
        if (event.key === 'Enter' || event.key === ' ') {
          const activeElement = document.activeElement;
          if (activeElement && activeElement.classList.contains('sakura-header')) {
            event.preventDefault();
            toggleCollapsible();
          }
        }
      });

      window.addEventListener('load', updateIframeHeight);
      window.addEventListener('resize', updateIframeHeight);
    </script>
  </body>
</html>
