    <style>
        :root {
            /* Palette: Japanese Gothic - Modern & Elegant */
            --bg-paper: #f4f1ea;
            /* Warm Washi Paper */
            --text-ink: #1a1a1a;
            /* Sumi Ink */
            --accent-red: #9e2a2b;
            /* Deep Crimson / Higanbana */
            --accent-gold: #c5a059;
            /* Muted Gold */
            --surface-white: #ffffff;
            --border-faint: rgba(26, 26, 26, 0.1);

            --font-serif: 'Shippori Mincho', 'Noto Serif JP', serif;
