        }

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            background-color: var(--bg-paper);
            background-image: radial-gradient(#e0dfd5 1px, transparent 1px);
            background-size: 20px 20px;
            color: var(--text-ink);
            font-family: var(--font-sans);
            line-height: 1.8;
            padding: 20px 16px;
            min-height: 100vh;
        }

        .layout-container {
            max-width: 960px;
            margin: 0 auto;
            position: relative;
        }

        /* Decorative Elements */
        .decor-flower {
            position: fixed;
            top: -50px;
            right: -50px;
            width: 300px;
            height: 300px;
            background: radial-gradient(circle, var(--accent-red) 0%, transparent 70%);
            opacity: 0.05;
            pointer-events: none;
            z-index: -1;
        }

        .decor-line {
            position: absolute;
            left: 20px;
            top: 0;
            bottom: 0;
            width: 1px;
            background: linear-gradient(to bottom, transparent, var(--accent-red), transparent);
            opacity: 0.3;
        }

        /* Header Section */
        header {
            text-align: center;
            margin-bottom: 60px;
            position: relative;
            padding: 40px 0;
            border-bottom: 1px solid var(--border-faint);
        }

        header::after {
            content: "JUDGEMENT";
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            font-size: 8rem;
            font-weight: 900;
            color: rgba(0, 0, 0, 0.03);
            letter-spacing: 1rem;
            z-index: -1;
            font-family: var(--font-serif);
            white-space: nowrap;
        }

        h1 {
            font-family: var(--font-serif);
            font-size: 3.5rem;
            font-weight: 500;
            letter-spacing: 0.2rem;
            margin-bottom: 10px;
            color: var(--text-ink);
        }

        .subtitle {
            font-family: var(--font-serif);
            color: var(--accent-red);
            font-size: 1.1rem;
            letter-spacing: 0.15rem;
            text-transform: uppercase;
            display: inline-block;
            position: relative;
            padding: 0 15px;
        }

        .subtitle::before,
        .subtitle::after {
            content: '♦';
            font-size: 0.8em;
            vertical-align: middle;
            opacity: 0.6;
            margin: 0 8px;
        }

        /* Hero/Cover Area */
