    <!-- Script for Entering Trial -->
    <script>
        // ===== 世界书操作 =====
        let worldBook = null;

        async function initWorldbook() {
            if (!worldBook) {
                if (typeof getCharWorldbookNames === 'function') {
                    worldBook = getCharWorldbookNames('current').primary;
                    console.log('[世界书] 初始化:', worldBook);
                } else {
                    console.warn('[世界书] getCharWorldbookNames 不可用');
                }
            }
            return worldBook;
        }

        // 设置单个条目的启用状态（按名称精确匹配）
        async function setWorldbookEntry(entryName, enabled) {
            if (!worldBook) {
                await initWorldbook();
            }
            if (!worldBook) {
                console.warn('[世界书] 世界书未初始化，无法操作条目');
                return false;
            }

            try {
                await updateWorldbookWith(worldBook, worldbook => {
                    return worldbook.map(entry => {
                        if (entry.name === entryName) {
                            console.log(`[世界书] ${entryName} → ${enabled ? '启用' : '禁用'}`);
                            return { ...entry, enabled: enabled };
                        }
                        return entry;
                    });
                });
                return true;
            } catch (e) {
                console.error('[世界书] 设置条目失败:', e);
                return false;
            }
        }

        // 按标签批量设置条目启用状态（名称包含指定字符）
        async function setEntriesEnabledByTag(tag, isEnabled) {
            if (!worldBook) {
                await initWorldbook();
            }
            if (!worldBook) {
                console.warn('[世界书] 世界书未初始化，无法操作条目');
                return false;
            }

            if (typeof getWorldbook !== 'function' || typeof replaceWorldbook !== 'function') {
                console.warn('[世界书] 世界书批量操作API不可用');
                return false;
            }

            console.log(`[世界书] 正在${isEnabled ? '启用' : '禁用'}包含"${tag}"的条目...`);

            try {
                const allEntries = await getWorldbook(worldBook);

                // 根据 entry.name 进行过滤
                const taggedEntries = allEntries.filter(entry => entry.name && entry.name.includes(tag));

                console.log(`[世界书] 找到 ${taggedEntries.length} 个包含"${tag}"的条目:`,
                    taggedEntries.map(e => ({ name: e.name, enabled: e.enabled })));

                let isChanged = false;

                const updatedEntries = allEntries.map(entry => {
                    if (entry.name && entry.name.includes(tag)) {
                        if (entry.enabled !== isEnabled) {
                            isChanged = true;
                            return { ...entry, enabled: isEnabled };
                        }
                    }
                    return entry;
                });

                if (isChanged) {
                    const changedCount = updatedEntries.filter(e => e.name && e.name.includes(tag) && e.enabled === isEnabled).length;
                    console.log(`[世界书] 正在更新 ${changedCount} 个条目的状态...`);
                    await replaceWorldbook(worldBook, updatedEntries);
                    console.log(`[世界书] 包含"${tag}"的条目已${isEnabled ? '启用' : '禁用'}`);
                } else {
                    console.log(`[世界书] 包含"${tag}"的条目状态无需更改`);
                }

                return true;

            } catch (error) {
                console.error(`[世界书] 批量操作失败:`, error);
                return false;
            }
        }

        // 剧情世界书命名规则
        const MAX_PLAYTHROUGHS = 3;
        const MAX_CHAPTERS = 6;

        function getWorldbookName(playthrough, chapter, suffix) {
            return `A${playthrough}_C${chapter}_${suffix}`;
        }

        // 关闭所有剧情世界书
        async function disableAllPlotWorldbooks() {
            const PHASES = ['日常', '案发搜查', '审判', '处刑尾声'];

            for (let p = 1; p <= MAX_PLAYTHROUGHS; p++) {
                for (let c = 1; c <= MAX_CHAPTERS; c++) {
                    await setWorldbookEntry(getWorldbookName(p, c, '总览'), false);
                    for (const phase of PHASES) {
                        await setWorldbookEntry(getWorldbookName(p, c, phase), false);
                    }
                }
            }
            console.log('[时间线] 所有剧情世界书已关闭');
        }

        // 开启指定周目第一章的世界书
        async function enableFirstChapterWorldbooks(playthrough) {
            // 先关闭所有剧情世界书
            await disableAllPlotWorldbooks();

            // 开启对应周目第一章的总览和日常
            await setWorldbookEntry(getWorldbookName(playthrough, 1, '总览'), true);
            await setWorldbookEntry(getWorldbookName(playthrough, 1, '日常'), true);

            console.log(`[时间线] 已开启 A${playthrough}_C1 的总览和日常世界书`);
        }

        // 根据时间线选择应用世界书配置和变量设置
        async function applyTimelineSettings(timeline) {
            console.log(`[时间线] 正在应用配置: ${timeline}`);

            try {
                await initWorldbook();

                if (!worldBook) {
                    console.warn('[时间线] 世界书未初始化，跳过配置');
                    return;
                }

                // 获取当前MVU数据
                let mvuData = null;
                if (typeof Mvu !== 'undefined' && typeof Mvu.getMvuData === 'function') {
                    try {
                        mvuData = Mvu.getMvuData({ type: 'message', message_id: 'latest' });
                    } catch (e) {
                        console.warn('[时间线] 获取MVU数据失败:', e);
                    }
                }

                // 无论选择哪个时间线，都先关闭三个后日谈高中事件世界书
                console.log('[时间线] 关闭后日谈高中事件世界书');
                await setWorldbookEntry('后日谈 - 高一事件', false);
                await setWorldbookEntry('后日谈 - 高二事件', false);
                await setWorldbookEntry('后日谈 - 高三事件', false);

                if (timeline === 'epilogue') {
                    // ===== 后日谈配置 =====
                    console.log('[时间线] 后日谈模式');

                    // 1. 关闭所有剧情世界书
                    await disableAllPlotWorldbooks();

                    // 2. 开启2️⃣标签，关闭1️⃣标签
                    await setEntriesEnabledByTag('2️⃣', true);
                    await setEntriesEnabledByTag('1️⃣', false);

                    // 3. 关闭血液规则和扣扣规则
                    await setWorldbookEntry('血液规则[mvu_plot]', false);
                    await setWorldbookEntry('特殊 - 扣扣转化', false);

                    // 4. 设置变量：game_mode = '2', chapter_manager.enabled = false
                    if (mvuData && mvuData.stat_data) {
                        mvuData.stat_data.game_mode = '2';
                        if (mvuData.stat_data.chapter_manager) {
                            mvuData.stat_data.chapter_manager.enabled = false;
                        }
                        await Mvu.replaceMvuData(mvuData, { type: 'message', message_id: 'latest' });
                        console.log('[时间线] 变量已设置: game_mode=2, chapter_manager.enabled=false');
                    }

                    showToast('✅ 后日谈模式已配置\n世界书已同步', 'success');

                } else {
                    // ===== 周目模式（1、2、3） =====
                    const playthrough = parseInt(timeline);
                    console.log(`[时间线] 第${playthrough}周目模式`);

                    // 1. 开启1️⃣标签，关闭2️⃣标签
                    await setEntriesEnabledByTag('1️⃣', true);
                    await setEntriesEnabledByTag('2️⃣', false);

                    // 2. 开启血液规则，关闭扣扣规则
                    await setWorldbookEntry('血液规则[mvu_plot]', true);
                    await setWorldbookEntry('特殊 - 扣扣转化', false);

                    // 3. 开启对应周目第一章的剧情世界书
                    await enableFirstChapterWorldbooks(playthrough);

                    // 4. 设置变量
                    if (mvuData && mvuData.stat_data) {
                        mvuData.stat_data.game_mode = '1';
                        if (mvuData.stat_data.chapter_manager) {
                            mvuData.stat_data.chapter_manager.enabled = true;
                            mvuData.stat_data.chapter_manager.playthrough = playthrough;
                            mvuData.stat_data.chapter_manager.chapter = 1;
                            mvuData.stat_data.chapter_manager.stage = { phase: '日常' };
                            mvuData.stat_data.chapter_manager.scene_name = getFirstSceneName(playthrough);
                        }
                        await Mvu.replaceMvuData(mvuData, { type: 'message', message_id: 'latest' });
                        console.log(`[时间线] 变量已设置: game_mode=1, playthrough=${playthrough}, chapter=1`);
                    }

                    showToast(`✅ 第${playthrough}周目已配置\n世界书已同步`, 'success');
                }

                // 重置扣扣规则勾选框状态
                const koukouCheckbox = document.getElementById('koukouMode');
                if (koukouCheckbox) {
                    koukouCheckbox.checked = false;
                }

                console.log('[时间线] 配置完成');

            } catch (error) {
                console.error('[时间线] 配置失败:', error);
                showToast('配置失败', 'error');
            }
        }

        // 获取各周目第一章的场景名称
        function getFirstSceneName(playthrough) {
            const FIRST_SCENES = {
                1: '01-噩梦与觉醒',
                2: '01-死亡回溯与觉醒',
                3: '01-死亡回溯的代价'
            };
            return FIRST_SCENES[playthrough] || '01';
        }

        // 切换扣扣规则
        async function toggleKoukouMode(enabled) {
            console.log(`[扣扣规则] 切换扣扣模式: ${enabled ? '开启' : '关闭'}`);

            // 扣扣模式开启时：禁用血液规则，启用扣扣转化
            // 扣扣模式关闭时：启用血液规则，禁用扣扣转化
            await setWorldbookEntry('血液规则[mvu_plot]', !enabled);
            await setWorldbookEntry('特殊 - 扣扣转化', enabled);

            if (enabled) {
                showToast('已开启扣扣规则', 'success');
            } else {
                showToast('已关闭扣扣规则', 'success');
            }
        }

        // 显示提示消息（使用酒馆内置的 toastr）
        function showToast(message, type = 'success') {
            // 检查 toastr 是否可用
            if (typeof toastr !== 'undefined') {
                switch (type) {
                    case 'success':
                        toastr.success(message);
                        break;
                    case 'error':
                        toastr.error(message);
                        break;
                    case 'warning':
                        toastr.warning(message);
                        break;
                    default:
                        toastr.info(message);
                }
            } else {
                // 降级方案：使用 console.log
                console.log(`[提示] ${type}: ${message}`);
            }
        }

        // 切换到开场白2
        async function switchToOpening(swipeId) {
            const btn = document.getElementById('enterTrial');

            // Visual feedback
            if (btn) {
                btn.style.opacity = '0.6';
                btn.style.pointerEvents = 'none';
                btn.innerText = '正在载入...';
            }

            try {
                const messages = await getChatMessages("0", { include_swipe: true });
                if (messages && messages[0].swipes && messages[0].swipes[swipeId]) {
                    await setChatMessage(messages[0].swipes[swipeId], 0, {
                        swipe_id: swipeId,
                        refresh: 'display_and_render_current'
                    });
                    showToast('已进入魔女监牢！', 'success');
                } else {
                    throw new Error(`开场白 ${swipeId + 1} 未找到，请确保已按顺序添加所有开场白。`);
                }
            } catch (error) {
                console.error('❌ 切换开场白失败:', error);
                showToast(`进入失败: ${error.message}`, 'error');

                // Reset button on error
                if (btn) {
                    btn.style.opacity = '1';
                    btn.style.pointerEvents = 'auto';
                    btn.innerText = '进入魔女监牢';
                }
            }
        }

        // ===== 时间线选择器逻辑 =====
        let selectedTimeline = null;
        let selectedSwipeId = null;

        const timelineOptions = document.querySelectorAll('.timeline-option');
        const enterSection = document.getElementById('enterSection');
        const koukouContainer = document.getElementById('koukouContainer');
        const enterBtn = document.getElementById('enterTrial');

        // 时间线选项点击事件
        timelineOptions.forEach(option => {
            option.addEventListener('click', async function () {
                // 移除所有选中状态
                timelineOptions.forEach(opt => opt.classList.remove('selected'));

                // 添加当前选中状态
                this.classList.add('selected');

                // 获取时间线信息
                selectedTimeline = this.dataset.timeline;
                selectedSwipeId = parseInt(this.dataset.swipe);

                // 显示进入按钮区域
                enterSection.classList.remove('hidden');

                // 根据时间线类型显示/隐藏扣扣规则选项
                if (selectedTimeline === 'epilogue') {
                    // 后日谈：隐藏扣扣规则，更改按钮文本
                    koukouContainer.style.display = 'none';
                    enterBtn.innerText = '开始后日谈';
                } else {
                    // 前三周目：显示扣扣规则，按钮文本为进入监牢
                    koukouContainer.style.display = 'flex';
                    enterBtn.innerText = '进入魔女监牢';
                }

                console.log(`[时间线] 选择: ${selectedTimeline}, 开场白ID: ${selectedSwipeId}`);

                // 应用时间线对应的世界书配置
                await applyTimelineSettings(selectedTimeline);
            });
        });

        // 进入按钮点击事件
        enterBtn.addEventListener('click', function (e) {
            e.preventDefault();
            if (selectedSwipeId !== null) {
                switchToOpening(selectedSwipeId);
            }
        });

        // 扣扣规则勾选框事件
        document.getElementById('koukouMode').addEventListener('change', function (e) {
            toggleKoukouMode(e.target.checked);
        });
    </script>
</body>

</html>
