            content: '✦';
            position: absolute;
            top: 15px;
            right: 20px;
            font-size: 2rem;
            color: var(--accent-gold);
            opacity: 0.3;
        }

        .preset-header {
            text-align: center;
            margin-bottom: 25px;
        }

        .preset-header h2 {
            font-family: var(--font-serif);
            font-size: 1.6rem;
            color: var(--text-ink);
            margin-bottom: 8px;
        }

        .preset-header p {
            color: #666;
            font-size: 0.95rem;
        }

        /* 预置列表样式 */
        .preset-list {
            display: flex;
            flex-direction: column;
            gap: 12px;
            max-width: 600px;
            margin: 0 auto;
        }

        .preset-item {
            padding: 20px 24px;
            cursor: pointer;
            border: 2px solid var(--border-faint);
            border-radius: 12px;
            background: var(--surface-white);
            transition: all 0.3s ease;
            position: relative;
            display: flex;
            align-items: center;
            gap: 16px;
        }

        .preset-item:hover {
            border-color: var(--accent-gold);
            box-shadow: 0 8px 25px rgba(197, 160, 89, 0.2);
            transform: translateY(-2px);
        }

        .preset-item.selected {
            border-color: var(--accent-red);
            background: linear-gradient(135deg, #fff9f9 0%, #fff 100%);
            box-shadow: 0 8px 30px rgba(158, 42, 43, 0.15);
        }

        .preset-item.selected::after {
            content: '✓';
            position: absolute;
            right: 20px;
            top: 50%;
            transform: translateY(-50%);
            width: 28px;
            height: 28px;
            background: var(--accent-red);
            color: white;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 14px;
            font-weight: bold;
        }

        .preset-icon {
            font-size: 2rem;
            width: 50px;
            height: 50px;
            display: flex;
            align-items: center;
            justify-content: center;
            background: linear-gradient(135deg, rgba(197, 160, 89, 0.1), rgba(158, 42, 43, 0.1));
            border-radius: 12px;
            flex-shrink: 0;
        }

        .preset-content {
            flex: 1;
        }

        .preset-name {
            font-family: var(--font-serif);
            font-size: 1.2rem;
            color: var(--text-ink);
            margin-bottom: 4px;
            font-weight: 600;
        }

        .preset-desc {
            font-size: 0.9rem;
            color: #666;
        }

        /* 自定义区域样式 */
        .custom-config-section {
            display: none;
            animation: fadeIn 0.3s ease;
        }

        .custom-config-section.visible {
            display: block;
        }

        @keyframes fadeIn {
            from {
                opacity: 0;
                transform: translateY(-10px);
            }

            to {
                opacity: 1;
                transform: translateY(0);
            }
        }

        .custom-action-bar {
            text-align: center;
            margin-top: 40px;
        }

        .current-preset-display {
            text-align: center;
            margin-top: 25px;
            padding: 15px 20px;
            background: rgba(158, 42, 43, 0.05);
            border-radius: 8px;
            font-family: var(--font-serif);
            border: 1px dashed rgba(158, 42, 43, 0.2);
        }

        .current-preset-display .label {
            color: #888;
            font-size: 0.85rem;
        }

        .current-preset-display .name {
            color: var(--accent-red);
            font-weight: 600;
            font-size: 1.1rem;
            margin-left: 8px;
        }

        .current-preset-display .status {
            display: block;
            margin-top: 8px;
            font-size: 0.85rem;
            color: #2e7d32;
        }

        /* 隐藏的主action-bar */
        .action-bar.hidden {
            display: none;
        }

        /* ===== 复选框样式 ===== */
        .checkbox-group {
            display: none;
            flex-wrap: wrap;
            gap: 20px;
            margin-top: 16px;
            padding: 16px 20px;
            background: rgba(197, 160, 89, 0.08);
            border: 1px solid rgba(197, 160, 89, 0.3);
            border-radius: 8px;
            align-items: center;
            animation: fadeIn 0.3s ease;
        }

        .checkbox-group.visible {
            display: flex;
        }

        .checkbox-group-label {
            font-family: var(--font-serif);
            font-weight: 600;
            color: var(--text-ink);
            margin-right: 8px;
        }

        .checkbox-container {
            display: flex;
            align-items: center;
            cursor: pointer;
            user-select: none;
            gap: 8px;
            position: relative;
        }

        .checkbox-container input {
            display: none;
        }

        .checkmark {
            width: 22px;
            height: 22px;
            border: 2px solid var(--accent-gold);
            border-radius: 4px;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s ease;
            background: var(--surface-white);
        }

        .checkbox-container input:checked+.checkmark {
            background: var(--accent-gold);
            border-color: var(--accent-gold);
        }

        .checkbox-container input:checked+.checkmark::after {
            content: '✓';
            color: white;
            font-size: 14px;
            font-weight: bold;
        }

        .checkbox-container:hover .checkmark {
            box-shadow: 0 0 10px rgba(197, 160, 89, 0.3);
            transform: scale(1.05);
        }

        .checkbox-label {
            font-family: var(--font-serif);
            font-size: 1rem;
            color: #444;
        }

        /* 高中选项展开区域 */
        .preset-item-wrapper {
            display: flex;
            flex-direction: column;
            gap: 0;
        }

        .preset-item-wrapper .preset-item {
            border-bottom-left-radius: 0;
            border-bottom-right-radius: 0;
        }

        .preset-item-wrapper .checkbox-group {
            border-top: none;
            border-top-left-radius: 0;
            border-top-right-radius: 0;
            margin-top: 0;
        }

        .preset-item-wrapper .preset-item:not(.selected)+.checkbox-group {
            display: none !important;
        }
    </style>
</head>

<body>

    <!-- 开局文本存储区域（通过占位符替换，使用 # 标题格式划分） -->
    <!-- 使用 textarea 存储开局文本（占位符会被替换） -->
    <textarea id="opening-content-store" style="display:none;">$1</textarea>

    <div class="decor-flower"></div>

    <div class="layout-container">

        <header class="page-header">
            <div class="page-subtitle">Character Configuration</div>
            <h1>开局设定配置</h1>
            <p style="color: #666; width: 80%; margin: 10px auto;">为即将开始的"后日谈"篇章定制专属的舞台与规则。</p>
        </header>

        <!-- Preset Selector Card - 三行列表模式 -->
        <section class="preset-selector-card">
            <div class="preset-header">
                <h2>🎭 选择舞台模板</h2>
                <p>选择一套预置配置，或自定义您的舞台背景与日历主题</p>
            </div>

            <div class="preset-list">
                <!-- 日式高中生活（带复选框展开） -->
                <div class="preset-item-wrapper">
                    <div class="preset-item" data-preset="highschool" onclick="selectPreset('highschool')">
                        <div class="preset-icon">🏫</div>
                        <div class="preset-content">
                            <div class="preset-name">日式高中生活</div>
                            <div class="preset-desc">日系高中校园生活，这是一段没有审判的平凡而珍贵的青春时光</div>
                        </div>
                    </div>
                    <!-- 高中年级事件复选框 -->
                    <div class="checkbox-group" id="highschool-options">
                        <span class="checkbox-group-label">📅 预置事件:</span>
                        <label class="checkbox-container">
                            <input type="checkbox" id="preset-year1" checked>
                            <span class="checkmark"></span>
                            <span class="checkbox-label">高一事件</span>
                        </label>
                        <label class="checkbox-container">
                            <input type="checkbox" id="preset-year2">
                            <span class="checkmark"></span>
                            <span class="checkbox-label">高二事件</span>
                        </label>
                        <label class="checkbox-container">
                            <input type="checkbox" id="preset-year3">
                            <span class="checkmark"></span>
                            <span class="checkbox-label">高三事件</span>
                        </label>
                    </div>
                </div>

                <!-- 半裸孤岛假日 -->
                <div class="preset-item" data-preset="island" onclick="selectPreset('island')">
                    <div class="preset-icon">🏝️</div>
                    <div class="preset-content">
                        <div class="preset-name">半裸孤岛假日</div>
                        <div class="preset-desc">平然色情喜剧，裸体避难所岛。所有人，保持半裸</div>
                    </div>
                </div>

                <!-- 自定义 -->
                <div class="preset-item" data-preset="custom" onclick="selectPreset('custom')">
                    <div class="preset-icon">✏️</div>
                    <div class="preset-content">
                        <div class="preset-name">自定义</div>
                        <div class="preset-desc">自定义舞台背景与日历事件主题</div>
                    </div>
                </div>
            </div>

            <!-- 当前预置状态显示 -->
            <div class="current-preset-display" id="current-preset-display" style="display: none;">
                <span class="label">当前选择:</span>
                <span class="name" id="current-preset-name"></span>
                <span class="status" id="current-preset-status"></span>
            </div>
        </section>

        <!-- 自定义配置区域 - 仅在选择自定义时显示 -->
        <div id="custom-config-section" class="custom-config-section">
            <!-- Section 1: Stage Background -->
            <section class="config-card">
                <div class="card-header">
                    <h2 class="card-title">
                        <span class="card-icon">✦</span> 自定义舞台背景
                    </h2>
                </div>
                <div class="editor-container">
                    <textarea id="stage-config" class="config-editor" placeholder="在此输入自定义背景设定..."></textarea>
                </div>
            </section>

            <!-- Section 2: Calendar Rules -->
            <section class="config-card">
                <div class="card-header">
                    <h2 class="card-title">
                        <span class="card-icon">📅</span> 自定义日历事件主题
                    </h2>
                </div>
                <div class="editor-container">
                    <textarea id="calendar-config" class="config-editor" placeholder="在此输入事件生成规则..."
                        style="min-height: 350px;"></textarea>
                </div>
            </section>

            <!-- Section 3: 自定义开场白 -->
            <section class="config-card">
                <div class="card-header">
                    <h2 class="card-title">
                        <span class="card-icon">💬</span> 指定开场白内容
                    </h2>
                </div>
                <p style="color: #666; font-size: 0.9rem; margin-bottom: 12px;">
                    此内容将发送给酒馆以生成开场消息
                </p>
                <div class="editor-container">
                    <textarea id="custom-opening" class="config-editor" placeholder="在此输入自定义开场白内容..."
                        style="min-height: 200px;"></textarea>
                </div>
            </section>

            <!-- 自定义模式的保存按钮 -->
            <div class="custom-action-bar">
                <button class="btn btn-primary btn-large" onclick="saveCustomConfig()">保存自定义配置到世界书</button>
            </div>
        </div>

        <!-- Confirmation Modal -->
        <div id="modal" class="modal-overlay">
            <div class="modal-content">
                <h3 class="modal-title" id="modal-title">确认操作</h3>
                <p class="modal-message" id="modal-message">此操作将覆盖现有世界书内容，是否继续？</p>
                <div class="modal-buttons">
                    <button class="btn btn-danger" id="modal-confirm">确认</button>
                    <button class="btn btn-cancel" onclick="closeModal()">取消</button>
                </div>
            </div>
        </div>

        <!-- 开始剧本按钮 -->
        <div class="action-bar">
            <button class="btn btn-primary btn-large" id="start-btn" onclick="startGeneration()">🎬 开始后日谈</button>
        </div>

        <div id="status-message" class="status-message"></div>

    </div>

    <script>
        // ===== 世界书名称配置 =====
        const worldbookConfig = {
            // 自定义世界书条目
            customStage: '2️⃣后日谈 - 自定义舞台背景',
            customCalendar: '2️⃣后日谈 - 自定义日历事件主题',

            // 高中模式世界书
            highschoolStage: '2️⃣后日谈 - 学校舞台背景',
            highschoolCalendar: '2️⃣⚙后日谈 - 学校日历事件主题',

            // 孤岛模式世界书
            islandStage: '2️⃣后日谈 - 孤岛舞台背景',
            islandCalendar: '2️⃣后日谈 - 孤岛日历事件主题'
        };

        // 年级事件世界书映射
        const yearEventWorldbooks = {
            'preset-year1': '后日谈 - 高一事件',
            'preset-year2': '后日谈 - 高二事件',
            'preset-year3': '后日谈 - 高三事件'
        };

        // 包含这些关键词的世界书需要被关闭
        const stageKeyword = '舞台背景';
        const calendarKeyword = '日历事件主题';

        // 当前选中的预置
        let currentPreset = null;
        let worldBook = null;

        // ===== 开局文本映射（从占位符解析） =====
        // 预置键名到标题名的映射
        const presetToTitle = {
            'highschool': '日式高中生活',
            'island': '半裸孤岛假日'
        };

        // ===== 特殊标签处理 =====
        // 源文件中的标签已预先转义为 {{ESCAPED_xxx}} 和 [[GT]]/[[LT]]

        // 还原特殊标签（写入聊天前调用）
        // 注意: 使用 '$' + '1' 拼接避免被模板替换系统误匹配
        function restoreSpecialTags(text) {
            const g1 = '$' + '1'; // 正则捕获组引用，拼接以避免被替换
            return text
                // 还原尖括号
                .replace(/\[\[GT\]\]/g, '>')
                .replace(/\[\[LT\]\]/g, '<')
                // 还原标签
                .replace(/\{\{ESCAPED_(\/?)update\}\}/gi, '<' + g1 + 'update>')
                .replace(/\{\{ESCAPED_(\/?)UpdateVariable\}\}/gi, '<' + g1 + 'UpdateVariable>')
                .replace(/\{\{ESCAPED_(\/?)Updatevariable\}\}/gi, '<' + g1 + 'Updatevariable>')
                .replace(/\{\{ESCAPED_(\/?)update_analysis\}\}/gi, '<' + g1 + 'update_analysis>')
                .replace(/\{\{ESCAPED_(\/?)json_patch\}\}/gi, '<' + g1 + 'json_patch>')
                .replace(/\{\{ESCAPED_(\/?)now_plot\}\}/gi, '<' + g1 + 'now_plot>')
                .replace(/\{\{ESCAPED_(\/?)pic\}\}/gi, '<' + g1 + 'pic>')
                .replace(/\{\{ESCAPED_(\/?)content\}\}/gi, '<' + g1 + 'content>');
        }

        // 解析开局文本
        const openingContents = {};
        (function parseOpeningContent() {
            const store = document.getElementById('opening-content-store');
            if (!store) {
                console.error('[配置界面] 未找到 opening-content-store 元素');
                return;
            }

            // textarea 直接用 .value 获取内容
            let rawText = store.value.replace(/^[\s\n]+/, '').replace(/[\s\n]+$/, '');

            // 源文件中的标签已经预先转义为 {{ESCAPED_xxx}} 和 [[GT]]/[[LT]]
            // 无需再次处理，直接解析即可

            // 按 # 标题解析
            let currentTitle = null;
            let currentContent = [];

            rawText.split('\n').forEach(line => {
                const trimmed = line.trim();
                if (trimmed.startsWith('# ')) {
                    // 保存上一个标题的内容
                    if (currentTitle) {
                        openingContents[currentTitle] = currentContent.join('\n').trim();
                        console.log(`[配置界面] 解析到标题 "${currentTitle}"，内容长度: ${openingContents[currentTitle].length}`);
                    }
                    // 开始新标题
                    currentTitle = trimmed.replace('# ', '').trim();
                    currentContent = [];
                } else if (currentTitle) {
                    currentContent.push(line);
                }
            });

            // 保存最后一个标题的内容
            if (currentTitle) {
                openingContents[currentTitle] = currentContent.join('\n').trim();
                console.log(`[配置界面] 解析到标题 "${currentTitle}"，内容长度: ${openingContents[currentTitle].length}`);
            }

            console.log('[配置界面] 已解析开局文本:', Object.keys(openingContents));
        })();

        // ===== 核心功能：选择预置 =====
        async function selectPreset(presetKey) {
            // 更新UI选中状态
            document.querySelectorAll('.preset-item').forEach(item => {
                item.classList.remove('selected');
            });
            const selectedItem = document.querySelector(`.preset-item[data-preset="${presetKey}"]`);
            if (selectedItem) {
                selectedItem.classList.add('selected');
            }

            currentPreset = presetKey;

            // 根据预置类型切换自定义区域显示
            const customSection = document.getElementById('custom-config-section');
            if (presetKey === 'custom') {
                customSection.classList.add('visible');
            } else {
                customSection.classList.remove('visible');
            }

            // 根据预置类型切换高中选项复选框显示
            const highschoolOptions = document.getElementById('highschool-options');
            if (presetKey === 'highschool') {
                highschoolOptions.classList.add('visible');
                // 重置年级复选框为默认状态并同步世界书
                resetYearCheckboxes();
                await syncYearCheckboxesToWorldbook();
            } else {
                highschoolOptions.classList.remove('visible');
                // 选择其他预置时，关闭所有年级事件世界书
                await disableAllYearEvents();
            }

            // 应用预置配置
            await applyPresetConfig(presetKey);
        }

        // ===== 年级复选框管理 =====
        // 重置年级复选框为默认状态（只勾选高一）
        function resetYearCheckboxes() {
            document.getElementById('preset-year1').checked = true;
            document.getElementById('preset-year2').checked = false;
            document.getElementById('preset-year3').checked = false;
        }

        // 同步年级复选框状态到世界书
        async function syncYearCheckboxesToWorldbook() {
            for (const [checkboxId, worldbookName] of Object.entries(yearEventWorldbooks)) {
                const checkbox = document.getElementById(checkboxId);
                if (checkbox) {
                    const isChecked = checkbox.checked;
                    await setWorldbookEntry(worldbookName, isChecked);
                    console.log(`[配置界面] ${worldbookName} → ${isChecked ? '启用' : '禁用'}`);
                }
            }
        }

        // 关闭所有年级事件世界书
        async function disableAllYearEvents() {
            for (const [checkboxId, worldbookName] of Object.entries(yearEventWorldbooks)) {
                await setWorldbookEntry(worldbookName, false);
                console.log(`[配置界面] ${worldbookName} → 禁用`);
            }
        }

        // ===== 应用预置配置 =====
        async function applyPresetConfig(presetKey) {
            try {
                showStatus('正在配置世界书...', 'success');

                await initWorldbook();
                if (!worldBook) {
                    showStatus('世界书未初始化，请确保在正确的环境中运行', 'error');
                    return;
                }

                // 1. 关闭所有包含"舞台背景"和"日历事件主题"的世界书
                await disableAllStageAndCalendarEntries();

                // 2. 根据选择开启对应的世界书
                let enabledEntries = [];
                let presetName = '';
                let presetIcon = '';

                switch (presetKey) {
                    case 'highschool':
                        await setWorldbookEntry(worldbookConfig.highschoolStage, true);
                        await setWorldbookEntry(worldbookConfig.highschoolCalendar, true);
                        enabledEntries = [worldbookConfig.highschoolStage, worldbookConfig.highschoolCalendar];
                        presetName = '日式高中生活';
                        presetIcon = '🏫';
                        break;

                    case 'island':
                        await setWorldbookEntry(worldbookConfig.islandStage, true);
                        await setWorldbookEntry(worldbookConfig.islandCalendar, true);
                        enabledEntries = [worldbookConfig.islandStage, worldbookConfig.islandCalendar];
                        presetName = '半裸孤岛假日';
                        presetIcon = '🏝️';
                        break;

                    case 'custom':
                        await setWorldbookEntry(worldbookConfig.customStage, true);
                        await setWorldbookEntry(worldbookConfig.customCalendar, true);
                        enabledEntries = [worldbookConfig.customStage, worldbookConfig.customCalendar];
                        presetName = '自定义';
                        presetIcon = '✏️';
                        break;
                }

                // 更新状态显示
                updatePresetDisplay(presetIcon, presetName, enabledEntries);
                showStatus(`已切换到: ${presetName}`, 'success');

                // 设置 game_mode 变量
                await setGameModeVariable();

                console.log(`[配置界面] 已应用预置: ${presetKey}`);
                console.log(`[配置界面] 已开启: ${enabledEntries.join(', ')}`);

            } catch (error) {
                console.error('[配置界面] 应用预置失败:', error);
                showStatus('配置失败: ' + error.message, 'error');
            }
        }

        // 设置 game_mode 变量为 2
        async function setGameModeVariable() {
            if (typeof Mvu !== 'undefined' && typeof Mvu.getMvuData === 'function') {
                try {
                    const mvuData = Mvu.getMvuData({ type: 'message', message_id: 'latest' });
                    if (mvuData && mvuData.stat_data) {
                        mvuData.stat_data.game_mode = '2';
                        await Mvu.replaceMvuData(mvuData, { type: 'message', message_id: 'latest' });
                        console.log('[配置界面] 变量已设置: game_mode=2');
                    }
                } catch (e) {
                    console.warn('[配置界面] 设置MVU变量失败:', e);
                }
            }
        }

        // ===== 关闭所有舞台背景和日历事件主题相关的世界书 =====
        async function disableAllStageAndCalendarEntries() {
            if (!worldBook) return;

            try {
                const allEntries = await getWorldbook(worldBook);
                let changedCount = 0;

                const updatedEntries = allEntries.map(entry => {
                    if (entry.name && (entry.name.includes(stageKeyword) || entry.name.includes(calendarKeyword))) {
                        if (entry.enabled) {
                            changedCount++;
                            console.log(`[配置界面] 关闭: ${entry.name}`);
                            return { ...entry, enabled: false };
                        }
                    }
                    return entry;
                });

                if (changedCount > 0) {
                    await replaceWorldbook(worldBook, updatedEntries);
                    console.log(`[配置界面] 已关闭 ${changedCount} 个舞台/日历相关条目`);
                }
            } catch (error) {
