        // 应用后日谈配置
        async function applyEpilogueSettings() {
            console.log('[后日谈] 正在应用配置');

            try {
                await initWorldbook();

                if (!worldBook) {
                    console.warn('[后日谈] 世界书未初始化，跳过配置');
                    return false;
