                // 1. 关闭所有剧情世界书
                await disableAllPlotWorldbooks();

                // 2. 开启2️⃣标签，关闭1️⃣标签
                // 注意：排除舞台背景和日历事件主题，这些已经在选择预置时配置好了
                const presetExcludeKeywords = [stageKeyword, calendarKeyword];
                await setEntriesEnabledByTag('2️⃣', true, presetExcludeKeywords);
