                // 3. 关闭血液规则和扣扣规则
                await setWorldbookEntry('血液规则[mvu_plot]', false);
                await setWorldbookEntry('特殊 - 扣扣转化', false);

                // 4. 设置变量：game_mode = '2', chapter_manager.enabled = false
                if (typeof Mvu !== 'undefined' && typeof Mvu.getMvuData === 'function') {
                    try {
                        const mvuData = Mvu.getMvuData({ type: 'message', message_id: 'latest' });
                        if (mvuData && mvuData.stat_data) {
