        // 关闭所有剧情世界书
        async function disableAllPlotWorldbooks() {
            const MAX_PLAYTHROUGHS = 3;
            const MAX_CHAPTERS = 6;
            const PHASES = ['日常', '案发搜查', '审判', '处刑尾声'];

            for (let p = 1; p <= MAX_PLAYTHROUGHS; p++) {
                for (let c = 1; c <= MAX_CHAPTERS; c++) {
                    const baseName = `A${p}_C${c}`;
                    await setWorldbookEntry(`${baseName}_总览`, false);
                    for (const phase of PHASES) {
                        await setWorldbookEntry(`${baseName}_${phase}`, false);
                    }
                }
            }
            console.log('[时间线] 所有剧情世界书已关闭');
        }

        // 按标签批量设置条目启用状态（名称包含指定字符）
        // excludeKeywords: 可选，排除包含这些关键词的条目
        async function setEntriesEnabledByTag(tag, isEnabled, excludeKeywords = []) {
            if (!worldBook) {
                await initWorldbook();
            }
            if (!worldBook) {
                console.warn('[世界书] 世界书未初始化，无法操作条目');
                return false;
            }

            if (typeof getWorldbook !== 'function' || typeof replaceWorldbook !== 'function') {
                console.warn('[世界书] 世界书批量操作API不可用');
                return false;
            }

            console.log(`[世界书] 正在${isEnabled ? '启用' : '禁用'}包含"${tag}"的条目...`);
            if (excludeKeywords.length > 0) {
                console.log(`[世界书] 排除关键词: ${excludeKeywords.join(', ')}`);
            }

            try {
                const allEntries = await getWorldbook(worldBook);

                // 筛选条目：包含tag，但不包含任何excludeKeywords
                const shouldProcess = (entry) => {
                    if (!entry.name || !entry.name.includes(tag)) return false;
                    for (const keyword of excludeKeywords) {
                        if (entry.name.includes(keyword)) return false;
                    }
                    return true;
                };

                const taggedEntries = allEntries.filter(shouldProcess);
                console.log(`[世界书] 找到 ${taggedEntries.length} 个符合条件的条目`);

                let isChanged = false;
                const updatedEntries = allEntries.map(entry => {
                    if (shouldProcess(entry)) {
                        if (entry.enabled !== isEnabled) {
                            isChanged = true;
                            return { ...entry, enabled: isEnabled };
                        }
                    }
                    return entry;
                });

                if (isChanged) {
                    await replaceWorldbook(worldBook, updatedEntries);
                    console.log(`[世界书] 包含"${tag}"的条目已${isEnabled ? '启用' : '禁用'}`);
                }

                return true;
            } catch (error) {
                console.error(`[世界书] 批量操作失败:`, error);
                return false;
            }
        }

