            // 年级复选框change事件：同步世界书状态
            const yearCheckboxes = ['preset-year1', 'preset-year2', 'preset-year3'];
            yearCheckboxes.forEach(id => {
                const checkbox = document.getElementById(id);
                if (checkbox) {
                    checkbox.addEventListener('change', async () => {
                        const worldbookName = yearEventWorldbooks[id];
                        if (worldbookName) {
                            try {
                                await setWorldbookEntry(worldbookName, checkbox.checked);
                                console.log(`[配置界面] ${worldbookName} → ${checkbox.checked ? '启用' : '禁用'}`);
                            } catch (e) {
                                console.warn(`[配置界面] 更新 ${worldbookName} 失败:`, e);
                            }
                        }
                    });
                }
            });
        });
    </script>
