    function safeDecodeURIComponent(str) {
      try { return decodeURIComponent(str); } catch (e) {
        try { return decodeURI(str); } catch (e2) { return str; }
      }
    }

    window.refreshImage = function (imageId, event) {
      const imageContent = document.getElementById(imageId);
      const img = imageContent.querySelector('img');
      if (!img) return;
      const button = event ? event.target.closest('.image-refresh-btn') : null;
      if (button) {
        button.style.transform = 'rotate(360deg)';
        button.style.transition = 'transform 0.5s ease';
        setTimeout(() => { button.style.transform = ''; }, 500);
      }
      img.style.opacity = '0.5';
      img.style.transition = 'opacity 0.3s ease';
      const currentSrc = img.src;
      try {
        const parts = currentSrc.split('/');
        const nsfwIndex = parts.findIndex(p => p === 'NSFW' || p === 'SFW' || p === 'ALTER');
        if (nsfwIndex === -1 || nsfwIndex + 2 >= parts.length) return;
        const category = parts[nsfwIndex];
        // ALTER使用SFW的数据
        const categoryForLookup = (category === 'ALTER') ? 'SFW' : category;
        const character = safeDecodeURIComponent(parts[nsfwIndex + 1]);
        const fileNameWithExt = safeDecodeURIComponent(parts[nsfwIndex + 2]);
        const fileName = fileNameWithExt.replace(/\.webp$/, '');

        // 尝试匹配带编号的格式：类型+数字
        const fileMatch = fileName.match(/^(.+?)(\d+)$/);
        let type, currentNumber;

        if (fileMatch) {
          // 有编号的情况：如 "心虚1"
          type = fileMatch[1];
          currentNumber = parseInt(fileMatch[2]);
        } else {
          // 无编号的情况：如 "心虚"，视为编号0或1
          type = fileName;
          currentNumber = 0; // 标记为无编号状态
        }

        const categoryData = IMAGE_LISTS[categoryForLookup];
        if (!categoryData) return;
        let characterData = categoryData[character];
        if (!characterData) {
          const normalizedChar = character.trim().normalize('NFC');
          characterData = categoryData[normalizedChar];
          if (!characterData) {
            const matched = Object.keys(categoryData).find(c =>
              c.trim().normalize('NFC') === normalizedChar || c.replace(/\s/g, '') === character.replace(/\s/g, '')
            );
            if (matched) characterData = categoryData[matched];
            else return;
          }
        }
        let maxNumber = characterData[type];
        if (!maxNumber) {
          const normalizedType = type.trim().normalize('NFC');
          maxNumber = characterData[normalizedType];
          if (!maxNumber) {
            const matched = Object.keys(characterData).find(t =>
              t.trim().normalize('NFC') === normalizedType || t.replace(/\s/g, '') === type.replace(/\s/g, '')
            );
            if (matched) maxNumber = characterData[matched];
            else return;
          }
        }
        let newNumber;
        if (maxNumber === 1) {
          newNumber = 1;
        } else {
          // 随机生成新编号，避免与当前编号相同
          do {
            newNumber = Math.floor(Math.random() * maxNumber) + 1;
          } while (currentNumber > 0 && newNumber === currentNumber);
        }
        // 始终生成带编号的文件名
        parts[nsfwIndex + 2] = encodeURIComponent(type + newNumber + '.webp');
        let newSrc = parts.join('/');

        // 如果开启了ALTER模式，替换SFW为ALTER
        if (localStorage.getItem('alter-mode') === 'true') {
          newSrc = newSrc.replace(/master\/SFW/, 'master/ALTER');
        }

        img.onload = function () {
          img.style.opacity = '1';
          img.style.width = imageSize + '%';
          img.style.maxWidth = imageSize + '%';
        };
        img.onerror = function () { img.style.opacity = '1'; };
        img.src = newSrc;
      } catch (e) { console.error('刷新图片失败:', e); }
    };

    function generateStyledNameHtml(config, normalizedName) {
      if (!config) {
        return `<span class="name-main">${normalizedName}</span>`;
      }

      const nameColor = config.color || 'var(--muted)';

      if (config.family_name) {
        const fName = config.family_name;
        const gName = config.given_name;
        // 姓氏首字：放大且染色
        let html = `<span class="name-large" style="color:${nameColor}">${fName[0]}</span>`;
        if (fName.length > 1) html += `<span class="name-normal">${fName.slice(1)}</span>`;

        // 移除过大的 margin-left，使用 CSS 默认间隔

        // 名字首字：放大但不染色
        html += `<span class="name-large">${gName[0]}</span>`;
        if (gName.length > 1) html += `<span class="name-normal">${gName.slice(1)}</span>`;
        return html;
      } else if (config.given_name) {
        const gName = config.given_name;
        let html = `<span class="name-large" style="color:${nameColor}">${gName[0]}</span>`;
        if (gName.length > 1) html += `<span class="name-normal">${gName.slice(1)}</span>`;
        return html;
      } else {
        if (normalizedName.length > 0) {
          return `<span class="name-large" style="color:${nameColor}">${normalizedName[0]}</span><span class="name-normal">${normalizedName.slice(1)}</span>`;
        }
        return `<span class="name-main" style="color:${nameColor}">${normalizedName}</span>`;
      }
    }

