            <div class="bubble-text">${processedDialogue}</div>
          </div>
        </div>
      </div>`;
    }

    // 处理对话内容（支持双语格式 + 论点交互）
    function processDialogueContent(dialogue) {
      // 移除对话内容中的角色名标记 {角色名}
      dialogue = dialogue.replace(/\{[^}]+\}/g, '').trim();

      // 论点解析：**论点** -> 交互式 spans（仅审判/魔女审判阶段显示）
      dialogue = dialogue.replace(/\*\*(.+?)\*\*/g, function (match, p1) {
        var phase = (typeof Mvu !== 'undefined' && Mvu.getMvuData) ? (Mvu.getMvuData({ type: 'message', message_id: 'latest' })?.stat_data?.chapter_manager?.stage?.phase || '') : '';
        if (phase === '审判' || phase === '魔女审判') {
          return '<span class="arg-point" onclick="showArgMenu(event, this)">' + p1 + '</span>';
        }
        return p1;
      });

      // 支持多种双语格式：
      // 「日文」（中文）、「日文」(中文)、『日文』（中文）、【日文】（中文）
      const patterns = [
        { regex: /「([^」]+)」（([^）]+)）/g, type: 'standard' },
        { regex: /「([^」]+)」\(([^)]+)\)/g, type: 'halfwidth' },
        { regex: /『([^』]+)』（([^）]+)）/g, type: 'alternate' },
        { regex: /【([^】]+)】（([^）]+)）/g, type: 'square' }
      ];

      let result = dialogue;
      patterns.forEach(({ regex }) => {
        result = result.replace(regex, (match, text1, text2) => {
          return `<div class="bilingual-dialogue">
        <div class="primary-text">「${text1}」</div>
        <div class="dialogue-divider"></div>
        <div class="secondary-text">（${text2}）</div>
      </div>`;
        });
      });

      // 如果没有双语格式，且不包含对话引号，则加上引号
      if (result === dialogue &&
        !dialogue.includes('「') && !dialogue.includes('『') &&
        !dialogue.includes('【')) {
        result = `「${dialogue}」`;
      }

      return result;
    }



