    function processTextContent() {
      const contentDiv = document.getElementById('readingContent');
      let rawText = contentDiv.innerHTML.trim();
      if (!rawText) return;
      const tagPatterns = [
        { regex: /<evidenceLog>([\s\S]*?)<\/evidenceLog>/gi, title: '证物收集', type: 'evidence-log' },
        { regex: /<Image>([\s\S]*?)<\/Image>/gi, title: '', type: 'image-tag' },
        { regex: /<pic>([\s\S]*?)<\/pic>/gi, title: '', type: 'image-tag' }
      ];
      const matches = [];
      tagPatterns.forEach(config => {
        let match;
        config.regex.lastIndex = 0;
        while ((match = config.regex.exec(rawText)) !== null) {
          matches.push({ index: match.index, length: match[0].length, content: match[1].trim(), title: config.title, type: config.type });
        }
      });
      matches.sort((a, b) => a.index - b.index);
      const htmlParts = [];
      let lastIndex = 0;
      matches.forEach(match => {
        const beforeText = rawText.substring(lastIndex, match.index);
        if (beforeText.trim()) htmlParts.push(processParagraphs(beforeText));
        if (match.type === 'image-tag') {
          htmlParts.push(createImageElement(match.content));
        } else if (match.type === 'evidence-log') {
          htmlParts.push(createEvidenceElement(match.content));
        }
        lastIndex = match.index + match.length;
      });
      const remainingText = rawText.substring(lastIndex);
      if (remainingText.trim()) htmlParts.push(processParagraphs(remainingText));
      contentDiv.innerHTML = htmlParts.join('');

      // 过滤全文中的 ** 符号
      removeAsterisks(contentDiv);
    }

    // 递归遍历文本节点，移除 ** 符号
    function removeAsterisks(node) {
      if (node.nodeType === Node.TEXT_NODE) {
        node.textContent = node.textContent.replace(/\*\*/g, '');
      } else {
        node.childNodes.forEach(removeAsterisks);
      }
    }

    function processParagraphs(text) {
      let cleanText = text.replace(/<\/?(?:evidenceLog|Image)(?!\s)>/gi, '');

      // 清理每行中重复的角色名标记：保留行首的 {角色名}，移除后续的 {角色名}
      // 例如 "{艾玛}{艾玛}「对话」" 变成 "{艾玛}「对话」"
      cleanText = cleanText.split('\n').map(line => {
        // 匹配行首的角色标记
        const firstTagMatch = line.match(/^(\s*\{[^}]+\})/);
        if (firstTagMatch) {
          const firstTag = firstTagMatch[1];
          const rest = line.substring(firstTag.length);
          // 移除剩余部分中的所有角色名标记
          const cleanRest = rest.replace(/\{[^}]+\}/g, '');
          return firstTag + cleanRest;
        }
        return line;
      }).join('\n');

      const lines = cleanText.split(/\n+/).filter(p => p.trim().length > 0);

      let resultHtml = '';
      let pendingDialogue = null;

      const flushPending = () => {
        if (pendingDialogue) {
          const mergedText = pendingDialogue.texts.map(t => processDialogueContent(t)).join('<br><br>');
          resultHtml += createDialogueElement(pendingDialogue.name, mergedText, true);
          pendingDialogue = null;
        }
      };

      // 辅助函数：检查是否可以合并
      const checkCanMerge = (normalizedName) => {
        if (!pendingDialogue) return false;
        if (pendingDialogue.normalizedName === normalizedName) return true;
        const c1 = CHARACTER_CONFIG[pendingDialogue.normalizedName];
        const c2 = CHARACTER_CONFIG[normalizedName];
        if (c1 && c2 && c1.avatar && c2.avatar && c1.avatar === c2.avatar) return true;
        return false;
      };

      for (let line of lines) {
        line = line.trim();

        // 跳过双花括号格式 {{...}}，这是情绪/动作描述，不作为对话处理
        if (/^\{\{.*\}\}/.test(line)) {
          flushPending();
          resultHtml += `<p>${escapeHtml(line)}</p>`;
          continue;
        }

        let rawName = null;
        let content = null;
        let normalizedName = null;

        // 1. 尝试花括号格式: {角色名}「对话」
        const braceNamePattern = /^[\s]*\{([^}]+)\}[\s]*(.+)$/;
        const braceMatch = line.match(braceNamePattern);

        if (braceMatch) {
          rawName = braceMatch[1].trim();
          content = braceMatch[2].trim();
          normalizedName = normalizeDisplayName(rawName);

          // 检查是否是有头像的已知角色
          const config = CHARACTER_CONFIG[normalizedName];
          if (!config || !config.avatar) {
            // 不是已知角色，过滤掉花括号标记，内容作为普通文本显示
            flushPending();
            resultHtml += `<p>${escapeHtml(content)}</p>`;
            continue;
          }
        }
        // 只处理明确的 {角色名} 格式

        if (rawName && content && normalizedName) {
          // 是对话行
          if (checkCanMerge(normalizedName)) {
            pendingDialogue.texts.push(content);
          } else {
            flushPending();
            pendingDialogue = {
              name: rawName,
              normalizedName: normalizedName,
              texts: [content]
            };
          }
        } else {
          // 非对话行，或无法识别的格式
          flushPending();
          resultHtml += processLineWithImages(line);
        }
      }
      flushPending();
      return resultHtml;
    }

    function processLineWithImages(line) {
      const tempDiv = document.createElement('div');
      tempDiv.innerHTML = line;
      const decodedLine = tempDiv.textContent || tempDiv.innerText || line;

      // 跳过双花括号格式 {{...}}
      if (/^\{\{.*\}\}/.test(decodedLine.trim())) {
        return `<p>${escapeHtml(line)}</p>`;
      }

      // 主要格式: {角色名}「对话」
      const braceNamePattern = /^[\s]*\{([^}]+)\}[\s]*(.+)$/;
      const braceMatch = decodedLine.match(braceNamePattern);

      if (braceMatch) {
        const rawName = braceMatch[1].trim();
        const normalizedName = normalizeDisplayName(rawName);
        // 校验是否是有头像的已知角色
        const config = CHARACTER_CONFIG[normalizedName];
        if (config && config.avatar) {
          return createDialogueElement(rawName, braceMatch[2].trim());
        }
        // 不是已知角色，过滤掉花括号标记，内容作为普通文本显示
        return `<p>${escapeHtml(braceMatch[2].trim())}</p>`;
      }

      // 只处理明确的 {角色名} 格式

      // 图片处理
      const imgRegex = /<img[^>]*>/i;
      if (imgRegex.test(decodedLine)) {
        const div = document.createElement('div');
        div.innerHTML = decodedLine;
        return createInteractiveImageContainer(div.innerHTML);
      } else {
        return `<p>${escapeHtml(line)}</p>`;
      }
    }

    function createImageElement(imageUrl) {
      let trimmedUrl = imageUrl.trim();
      if (!trimmedUrl) return '';

      // 处理 <pic> 标签的相对路径格式，如 "SFW/希罗/通常1"
      // 补全为完整URL
      if (/^(SFW|NSFW)\//.test(trimmedUrl)) {
        // 如果没有.webp后缀，添加它
        if (!trimmedUrl.endsWith('.webp')) {
          trimmedUrl = trimmedUrl + '.webp';
        }
        trimmedUrl = 'https://gitgud.io/Rown/moshen/-/raw/master/' + trimmedUrl;
      }

      const imgTag = `<img src="${escapeHtml(trimmedUrl)}" alt="图片" loading="lazy">`;
      return createInteractiveImageContainer(imgTag);
    }

    // 辅助函数：为缺少编号的图片URL自动添加随机编号
    function autoAssignImageNumber(imgSrc) {
      try {
        const parts = imgSrc.split('/');
        const nsfwIndex = parts.findIndex(p => p === 'NSFW' || p === 'SFW');
        if (nsfwIndex === -1 || nsfwIndex + 2 >= parts.length) return imgSrc;

        const category = parts[nsfwIndex];
        const character = safeDecodeURIComponent(parts[nsfwIndex + 1]);
        const fileNameWithExt = safeDecodeURIComponent(parts[nsfwIndex + 2]);
        const fileName = fileNameWithExt.replace(/\.webp$/, '');

        // 检查是否已有编号
        const fileMatch = fileName.match(/^(.+?)(\d+)$/);
        if (fileMatch) return imgSrc; // 已有编号，不处理

        // 无编号，尝试从IMAGE_LISTS获取最大编号并随机分配
        const type = fileName;
        const categoryData = IMAGE_LISTS[category];
        if (!categoryData) return imgSrc;

        let characterData = categoryData[character];
        if (!characterData) {
          const normalizedChar = character.trim().normalize('NFC');
          characterData = categoryData[normalizedChar];
          if (!characterData) {
            const matched = Object.keys(categoryData).find(c =>
              c.trim().normalize('NFC') === normalizedChar || c.replace(/\s/g, '') === character.replace(/\s/g, '')
            );
            if (matched) characterData = categoryData[matched];
            else return imgSrc;
          }
        }

        let maxNumber = characterData[type];
        if (!maxNumber) {
          const normalizedType = type.trim().normalize('NFC');
          maxNumber = characterData[normalizedType];
          if (!maxNumber) {
            const matched = Object.keys(characterData).find(t =>
              t.trim().normalize('NFC') === normalizedType || t.replace(/\s/g, '') === type.replace(/\s/g, '')
            );
            if (matched) maxNumber = characterData[matched];
            else return imgSrc;
          }
        }

        // 随机生成编号
        const newNumber = Math.floor(Math.random() * maxNumber) + 1;
        parts[nsfwIndex + 2] = encodeURIComponent(type + newNumber + '.webp');
        return parts.join('/');
      } catch (e) {
        console.error('自动分配图片编号失败:', e);
        return imgSrc;
      }
    }

    // 辅助函数：生成交互式图片容器 HTML
    function createInteractiveImageContainer(imgContent) {
      const uniqueId = 'img-' + Math.random().toString(36).substr(2, 9);
      const autoExpand = localStorage.getItem('image-auto-expand') !== 'false'; // 默认展开
      const expandedClass = autoExpand ? ' expanded' : '';
      const buttonClass = autoExpand ? ' expanded' : '';
      const buttonText = autoExpand ? '收起插画' : '查看插画';

      // 提取img标签中的src，检查并自动分配编号
      const srcMatch = imgContent.match(/src=["']([^"']+)["']/i);
      if (srcMatch) {
        const originalSrc = srcMatch[1];
        const newSrc = autoAssignImageNumber(originalSrc);
        if (newSrc !== originalSrc) {
          imgContent = imgContent.replace(originalSrc, newSrc);
        }
        // 为NSFW图片添加onload事件，记录到CG收集缓存
        if (newSrc.includes('/NSFW/')) {
          imgContent = imgContent.replace(/<img\s/i, '<img onload="recordCGUnlock(this.src)" ');
        }
      }

      return `<div class="image-container">
        <div style="display:flex;justify-content:center;align-items:center;gap:8px;">
          <button class="image-toggle-btn${buttonClass}" onclick="toggleImage('${uniqueId}')">
            <span class="image-toggle-text">${buttonText}</span>
          </button>
          <button class="image-refresh-btn" onclick="refreshImage('${uniqueId}', event)" title="随机切换图片">↻</button>
        </div>
        <div class="image-content${expandedClass}" id="${uniqueId}" style="text-align:center;">
          ${imgContent}
        </div>
      </div>`;
    }



    function createEvidenceElement(contentMatches) {
      // 简约风格证物列表
      // 解析格式：证物名: xxx \n 类型: xxx \n 描述: xxx
      // 多个证物之间用空行分割
      const rawItems = contentMatches.trim().split(/\n\s*\n/);
      let itemsHtml = '';
      let count = 0;

      rawItems.forEach(itemStr => {
        if (!itemStr.trim()) return;

        const nameMatch = itemStr.match(/证物名[:：]\s*(.+)/);
        const typeMatch = itemStr.match(/类型[:：]\s*(.+)/);
        const descMatch = itemStr.match(/描述[:：]\s*(.+)/);

        if (nameMatch) {
          count++;
          const name = nameMatch[1].trim();
          const type = typeMatch ? typeMatch[1].trim() : '未分类';
          const desc = descMatch ? descMatch[1].trim() : '';

          itemsHtml += `
            <div class="evidence-item">
                <div class="evidence-header">
                    <span class="ev-name">${name}</span>
                    <span class="ev-type">${type}</span>
                </div>
                <div class="evidence-desc">${desc}</div>
            </div>`;
        }
      });

      if (count === 0) return '';

      return `
      <div class="evidence-container">
        <details class="evidence-details">
            <summary class="evidence-summary">
                <span class="ev-title">获得新证据 (${count})</span>
                <span class="ev-toggle">▼</span>
            </summary>
            <div class="evidence-list">
                ${itemsHtml}
            </div>
        </details>
      </div>`;
    }

    function escapeHtml(text) {
      const tempDiv = document.createElement('div');
      tempDiv.innerHTML = text;
      const decodedText = tempDiv.textContent || tempDiv.innerText || '';
      const div = document.createElement('div');
      div.textContent = decodedText;
      return div.innerHTML;
    }

