        tagContainer.className = 'evidence-tag';
        // 插入到证据按钮后面
        const evidenceBtn = inputWrapper.querySelector('.arg-evidence-btn');
        if (evidenceBtn) {
          evidenceBtn.after(tagContainer);
        } else {
          inputWrapper.prepend(tagContainer);
        }
      }

      tagContainer.innerHTML = `${name}<span class="evidence-tag-remove">✕</span>`;
      tagContainer.querySelector('.evidence-tag-remove').addEventListener('click', function (e) {
        e.stopPropagation();
        removeSelectedEvidence();
      });

      // 聚焦输入框
      if (input) input.focus();
    }

    // 移除选中的证据
    function removeSelectedEvidence() {
      selectedEvidence = null;
      const tag = document.querySelector('.evidence-tag');
      if (tag) tag.remove();
    }

    // Mount to window for onclick access
    function submitArg(btn) {
      const menu = btn.closest('.arg-menu');
      const container = menu.querySelector('.arg-input-box');
      if (!container) {
        console.error('找不到 arg-input-box');
        return;
      }
      const prefix = container.querySelector('.arg-prefix').textContent;
      const input = container.querySelector('.arg-input');
      const val = input.value.trim();
      const type = input.dataset.type;
      const character = window._currentArgCharacter || '';

      // 构建发送消息：【类型：角色的论点"论点内容"】用户输入
      let message = '';
      const charPart = character ? `${character}的论点` : '论点';

      // 如果是出示证据且选中了证据
      if (type === '出示证据' && selectedEvidence) {
        message = `【${type}：${charPart}"${currentArgPoint}"】出示【${selectedEvidence.name}】（${selectedEvidence.description}）`;
        if (val) {
          message += ` ${val}`;
        }
      } else {
        // 其他类型
        message = `【${type}：${charPart}"${currentArgPoint}"】`;
        if (val) {
          message += val;
        }
      }

      const command = `/send ${message} | /trigger await=true`;

      if (typeof triggerSlash === 'function') {
        try {
          triggerSlash(command);
          showSettingsMessage(`✅ 已发送: ${message}`);
        } catch (e) {
          console.error('发送失败:', e);
          showSettingsMessage(`❌ 发送失败，请手动输入`);
        }
      } else {
        console.warn('SillyTavern API 不可用');
        showSettingsMessage(`⚠️ API不可用，请手动输入: ${message}`);
      }

      // 清理状态
      selectedEvidence = null;
      removeArgMenu();
    };

    function positionMenu(menu, target) {
      const rect = target.getBoundingClientRect();
      const menuRect = menu.getBoundingClientRect();

      let top = rect.bottom + 8;
      let left = rect.left + (rect.width / 2) - (menuRect.width / 2);

      // Boundary checks
      if (left < 10) left = 10;
      if (left + menuRect.width > window.innerWidth - 10) left = window.innerWidth - menuRect.width - 10;
      if (top + menuRect.height > window.innerHeight - 10) top = rect.top - menuRect.height - 8; // Flip to top if no space

      menu.style.top = `${top}px`;
      menu.style.left = `${left}px`;
    }

    function removeArgMenu() {
      if (activeArgMenu) {
        activeArgMenu.remove();
        activeArgMenu = null;
      }
    }

    // Global click to close menu
    document.addEventListener('click', (e) => {
      if (activeArgMenu && !activeArgMenu.contains(e.target)) {
        removeArgMenu();
      }
    });

    let readingFontSize = 18;
    let imageSize = 70; // 默认70%

    document.addEventListener('DOMContentLoaded', () => {
      processTextContent();
      requestAnimationFrame(() => {
        initThemeSwitcher();
        initSettings();
        const savedReadingFontSize = localStorage.getItem('readingFontSize');
        readingFontSize = savedReadingFontSize ? parseInt(savedReadingFontSize) : 18;
        const readingContent = document.querySelector('.reading-content');
        if (readingContent) readingContent.style.fontSize = readingFontSize + 'px';
        const savedImageSize = localStorage.getItem('imageSize');
        imageSize = savedImageSize !== null ? parseInt(savedImageSize) : 70; // 默认70%
        applyImageSize();
      });
    });

    /* Merged into window.setTheme / applyTheme logic above to remove duplication */

    function initSettings() {
      const settingsBtn = document.getElementById('settingsBtn');
      const settingsPanel = document.getElementById('settingsPanel');
      const imageToggle = document.getElementById('imageToggle');
      const dialogueFontToggle = document.getElementById('dialogueFontToggle');
      if (!settingsBtn || !settingsPanel || !imageToggle) return;
      if (localStorage.getItem('image-auto-expand') !== 'false') imageToggle.classList.add('active'); // 默认展开

      // 统一对白字体大小：PC端默认开启，移动端默认关闭
      const isMobile = window.innerWidth <= 768;
      const savedDialogueFont = localStorage.getItem('unified-dialogue-font');
      let dialogueFontEnabled;
      if (savedDialogueFont !== null) {
        dialogueFontEnabled = savedDialogueFont === 'true';
      } else {
        dialogueFontEnabled = !isMobile; // PC默认开，移动端默认关
      }
      if (dialogueFontEnabled) {
        dialogueFontToggle.classList.add('active');
        document.body.classList.add('unified-dialogue-font');
      }

      settingsBtn.addEventListener('click', function (e) { e.stopPropagation(); settingsPanel.classList.toggle('active'); });
      imageToggle.addEventListener('click', function () {
        this.classList.toggle('active');
        const isActive = this.classList.contains('active');
        localStorage.setItem('image-auto-expand', isActive);
        showSettingsMessage(isActive ? '已开启默认展开插画' : '已关闭默认展开插画');
      });

      dialogueFontToggle.addEventListener('click', function () {
        this.classList.toggle('active');
        const isActive = this.classList.contains('active');
        localStorage.setItem('unified-dialogue-font', isActive);
        document.body.classList.toggle('unified-dialogue-font', isActive);
        showSettingsMessage(isActive ? '已统一对白与正文字体大小' : '已恢复对白独立字体大小');
      });

      // 魔女化立绘开关
      const alterModeToggle = document.getElementById('alterModeToggle');
      if (alterModeToggle) {
        if (localStorage.getItem('alter-mode') === 'true') {
          alterModeToggle.classList.add('active');
        }
        alterModeToggle.addEventListener('click', function () {
          this.classList.toggle('active');
          const isActive = this.classList.contains('active');
          localStorage.setItem('alter-mode', isActive);
          // 即时更新所有图片
          toggleAlterModeImages(isActive);
          showSettingsMessage(isActive ? '已开启魔女化立绘' : '已关闭魔女化立绘');
        });
      }

      document.addEventListener('click', function (e) {
        if (!settingsPanel.contains(e.target) && !settingsBtn.contains(e.target)) settingsPanel.classList.remove('active');
      });
    }

    // 魔女化立绘：单张图片转换
    function applyAlterModeToImage(img) {
      const alterModeEnabled = localStorage.getItem('alter-mode') === 'true';
      const currentSrc = img.src;

      // 使用正则检查和替换 master/SFW 或 master/ALTER
      const hasSFW = /master\/SFW/.test(currentSrc);
      const hasALTER = /master\/ALTER/.test(currentSrc);

      if (!hasSFW && !hasALTER) return;

      let newSrc;
      if (alterModeEnabled && hasSFW) {
        newSrc = currentSrc.replace(/master\/SFW/, 'master/ALTER');
      } else if (!alterModeEnabled && hasALTER) {
        newSrc = currentSrc.replace(/master\/ALTER/, 'master/SFW');
      } else {
        return;
      }

      const originalSrc = currentSrc;
      img.style.opacity = '0.5';
      img.style.transition = 'opacity 0.3s ease';
      img.onload = function () {
        img.style.opacity = '1';
      };
      img.onerror = function () {
        img.src = originalSrc;
        img.style.opacity = '1';
      };
      img.src = newSrc;
    }

    // 魔女化立绘切换：更新所有已存在的图片
    function toggleAlterModeImages(enableAlter) {
      document.querySelectorAll('.image-content img, .reading-content img').forEach(img => {
        applyAlterModeToImage(img);
      });
    }

    // 监听DOM变化，对新加入的图片自动应用ALTER模式
    const alterModeObserver = new MutationObserver(function (mutations) {
      const alterModeEnabled = localStorage.getItem('alter-mode') === 'true';
      if (!alterModeEnabled) return;

      mutations.forEach(function (mutation) {
        mutation.addedNodes.forEach(function (node) {
          if (node.nodeType !== 1) return; // 只处理元素节点

          // 如果新增的节点是img
          if (node.tagName === 'IMG') {
            applyAlterModeToImage(node);
          }
          // 如果新增的节点包含img
          if (node.querySelectorAll) {
            node.querySelectorAll('img').forEach(img => {
              applyAlterModeToImage(img);
            });
          }
        });
      });
    });

    // 启动观察器
    alterModeObserver.observe(document.body, {
      childList: true,
      subtree: true
    });

    function showSettingsMessage(message) {
      const messageDiv = document.createElement('div');
      messageDiv.className = 'toast-message';
      messageDiv.textContent = message;
      document.body.appendChild(messageDiv);
      setTimeout(() => messageDiv.remove(), 2000);
    }

    // Theme setter helper
    const applyTheme = (theme) => {
      document.body.setAttribute('data-theme', theme);
      localStorage.setItem('kivotos-theme', theme);
      localStorage.setItem('theme', theme); // compatible backup
      document.querySelectorAll('.control-btn[onclick^="setTheme"]').forEach(btn => {
        btn.classList.toggle('active', btn.getAttribute('onclick').includes(`'${theme}'`));
      });
    };

    // Expose for HTML onclick
    window.setTheme = applyTheme;

    function initThemeSwitcher() {
      const savedTheme = localStorage.getItem('kivotos-theme') || 'warm-white';
      applyTheme(savedTheme);
    }

    function adjustReadingFontSize(delta) {
      readingFontSize = Math.max(12, Math.min(28, readingFontSize + delta));
      const readingContent = document.querySelector('.reading-content');
      if (readingContent) readingContent.style.fontSize = readingFontSize + 'px';
      localStorage.setItem('readingFontSize', readingFontSize);
    }

    function adjustImageSize(delta) {
      imageSize = Math.max(30, Math.min(200, imageSize + delta));
      applyImageSize();
      localStorage.setItem('imageSize', imageSize);
      showSettingsMessage(`插画大小: ${imageSize}%`);
    }

    function applyImageSize() {
      document.querySelectorAll('.image-content img').forEach(img => {
        img.style.width = imageSize + '%';
        img.style.maxWidth = imageSize + '%';
        img.style.height = 'auto';
      });
    }
  </script>
</body>

</html>
